#include<iostream>#include<vector>#include<algorithm>using namespace std;#define ll long longint main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int t;    cin>>t;    while(t--){        ll n,k;        cin>>n>>k;        vector<vector<ll>> a(n,vector<ll>(n));        for(int i=0;i<n;i++){            for(int j=0;j<n;j++){                cin>>a[i][j];            }         }        ll cnt=0;        for(int i=0;i<n;i++){            for(int j=0;j<n;j++){                if(a[i][j]!=a[n-1-i][n-1-j]){                    cnt++;                }            }        }        cnt/=2;        if(cnt>k){            cout<<"no\n";            continue;        }                ll temp= k-cnt;        if(temp%2==0){            cout<<"yes\n";        }        else{            if(n%2==1){                cout<<"yes\n";            }            else{                cout<<"no\n";            }        }    }}